class Animal {
  String name;

  Animal(this.name);

  void eat() {
    print('$name is eating.');
  }
}

class Dog extends Animal {
  Dog(String name) : super(name);

  void bark() {
    print('$name is barking.');
  }
}

void main() {
  var dog = Dog('Buddy');
  dog.eat();  // Inherited from Animal
  dog.bark(); // Defined in Dog
}

class Person {
  String name;
  int age;

  Person(this.name, this.age);

  void introduce() {
    print('Hi, I am $name and I am $age years old.');
  }
}

class Student extends Person {
  String school;

  Student(String name, int age, this.school) : super(name, age);

  @override
  void introduce() {
    super.introduce(); // Call the superclass method
    print('I study at $school.');
  }
}

void main() {
  var student = Student('Alice', 20, 'Dart University');
  student.introduce();
}

class Shape {
  void draw() {
    print('Drawing a shape.');
  }
}

class Circle extends Shape {
  @override
  void draw() {
    print('Drawing a circle.');
  }
}

void main() {
  Shape shape = Circle();
  shape.draw(); // Output: Drawing a circle.
}

class Vehicle {
  String brand;

  Vehicle(this.brand); // No default constructor
}

class Car extends Vehicle {
  String model;

  Car(String brand, this.model) : super(brand); // Must call super
}

void main() {
  var car = Car('Toyota', 'Camry');
}

